#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e5+5;
const int K = N*400;
struct qry{int opt,l,r,k;}q[N];
struct SegT{int sum,ls,rs;}t[K];
int n,m,Q,len,a[N],Ls[N];
int node_cnt,Rt[N],tmr[2][25],cnt[2];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void update(int &u,int l,int r,int p,int k){
    if(!u)u=(++node_cnt);
    t[u].sum+=k;if(l==r)return;
    int mid=(l+r)>>1;
    if(p<=mid)update(t[u].ls,l,mid,p,k);
    else update(t[u].rs,mid+1,r,p,k);
}
void Pre_upd(int x,int val){
    int p=lower_bound(Ls+1,Ls+len+1,a[x])-Ls;
    for(;x<=n;x+=x&-x)update(Rt[x],1,len,p,val);return;
}
int Ask_query(int l,int r,int k){
    if(l==r)return l;
    int mid=(l+r)>>1,res=0;
    for(int i=1;i<=cnt[1];i++)res+=t[t[tmr[1][i]].ls].sum;
    for(int i=1;i<=cnt[0];i++)res-=t[t[tmr[0][i]].ls].sum;
    if(k<=res){
        for(int i=1;i<=cnt[1];i++)tmr[1][i]=t[tmr[1][i]].ls;
        for(int i=1;i<=cnt[0];i++)tmr[0][i]=t[tmr[0][i]].ls;
        return Ask_query(l,mid,k);
    }else{
        for(int i=1;i<=cnt[1];i++)tmr[1][i]=t[tmr[1][i]].rs;
        for(int i=1;i<=cnt[0];i++)tmr[0][i]=t[tmr[0][i]].rs;
        return Ask_query(mid+1,r,k-res);
    }
}
int Pre_query(int l,int r,int k){
    memset(tmr,0,sizeof(tmr));
    cnt[0]=0,cnt[1]=0;
    for(int i=r;i;i-=i&-i)tmr[1][++cnt[1]]=Rt[i];
    for(int i=l-1;i;i-=i&-i)tmr[0][++cnt[0]]=Rt[i];
    return Ask_query(1,len,k);
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),Ls[++len]=a[i];
    for(int i=1;i<=Q;i++){
        char opt;cin>>opt;
        if(opt=='Q')q[i].opt=1,q[i].l=read(),q[i].r=read(),q[i].k=read();
        else q[i].opt=0,q[i].l=read(),q[i].k=read(),Ls[++len]=q[i].k;
    }sort(Ls+1,Ls+len+1);
    len=unique(Ls+1,Ls+len+1)-Ls-1;
    for(int i=1;i<=n;i++)Pre_upd(i,1);
    for(int i=1;i<=Q;i++){
        auto [opt,l,r,k]=q[i];
        if(opt)cout<<Ls[Pre_query(l,r,k)]<<"\n";
        else Pre_upd(l,-1),a[l]=k,Pre_upd(l,1);
    }
    return 0;
}
